SELECT bs."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.natural_gas.total.energy_consumption..kwh" * bs.weight) AS "natural_gas.total.energy_consumption..kwh", sum(CASE WHEN (coalesce(bs."out.natural_gas.total.energy_consumption..kwh", 0) != 0) THEN 1 ELSE 0 END * bs.weight) AS "natural_gas.total.energy_consumption..kwh__nonzero_units_count" FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs.state = 'CO' GROUP BY 1 ORDER BY 1